import React from 'react';

function AlarmPanel({ alarmState, systemActive, onDeactivateAlarm, onActivateSystem, onDeactivateSystem }) {
  return (
    <div className="panel">
      <h3>🚨 Alarm Kontrola</h3>

      <div className={`alarm-status ${alarmState ? 'active' : 'inactive'}`}>
        {alarmState ? '⚠️ ALARM JE AKTIVAN!' : '✅ Alarm je isključen'}
      </div>

      <div className={`system-status ${systemActive ? 'active' : 'inactive'}`}>
        {systemActive ? '🔒 Sigurnosni sistem AKTIVAN' : '🔓 Sigurnosni sistem neaktivan'}
      </div>

      <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
        {alarmState && (
          <button className="btn btn-danger" onClick={onDeactivateAlarm}>
            🔕 Isključi Alarm
          </button>
        )}

        {!systemActive ? (
          <button className="btn btn-warning" onClick={onActivateSystem}>
            🔐 Aktiviraj Sigurnosni Sistem
          </button>
        ) : (
          <button className="btn btn-success" onClick={onDeactivateSystem}>
            🔓 Deaktiviraj Sigurnosni Sistem
          </button>
        )}
      </div>

      <div style={{ marginTop: '15px', fontSize: '0.85rem', color: 'rgba(255,255,255,0.7)' }}>
        <p>ℹ️ Alarm se aktivira kada:</p>
        <ul style={{ marginLeft: '20px', marginTop: '5px' }}>
          <li>Vrata ostanu otvorena duže od 5 sekundi</li>
          <li>Sistem je aktivan i detektovan je pokret</li>
          <li>Nema osoba u objektu a detektovan je pokret</li>
          <li>GSG senzor detektuje značajan pomeraj</li>
        </ul>
      </div>
    </div>
  );
}

export default AlarmPanel;
